beforeExample:
package org.eclipse.jdt.internal.ui.problems;

import org.eclipse.core.resources.IMarker;

public class MarkerSeverityChecker {
    public int getSeverityValue(IMarker marker) {
        int val = marker.getAttribute(IMarker.SEVERITY, -1);
        if (val == IMarker.SEVERITY_WARNING || val == IMarker.SEVERITY_ERROR) {
            return val;
        }
        return 0;
    }
}

afterExample:
package org.eclipse.jdt.internal.ui.problems;

import org.eclipse.core.resources.IMarker;

public class MarkerSeverityChecker {
    public int getSeverityValue(IMarker marker) {
        int val = marker.getAttribute(IMarker.SEVERITY, -1);
        if (val == IMarker.SEVERITY_INFO || val == IMarker.SEVERITY_WARNING || val == IMarker.SEVERITY_ERROR) {
            return val;
        }
        return 0;
    }
}

